inline size_t get_baseline_count() {
  return get_baselines_table().size();
}

inline const FamilyLaneBaseline &get_baseline_by_index(size_t index) {
  return get_baselines_table().at(index);
}

inline const FamilyLaneBaseline *get_baseline(Slice family_id, Slice route_lane) {
  for (const auto &b : get_baselines_table()) {
    if (b.family_id == family_id && b.route_lane == route_lane) {
      return &b;
    }
  }
  return nullptr;
}

